from langgraph.checkpoint.base import BaseCheckpointSaver, Checkpoint, CheckpointMetadata
from typing import Iterator

class RedisCheckpointer(BaseCheckpointSaver):
    def __init__(self, redis_client):
        super().__init__()
        self.redis = redis_client

    def get_tuple(self, config: dict):
        thread_id = config["configurable"]["thread_id"]
        data = self.redis.get(f"checkpoint:{thread_id}:latest")
        if data is None:
            return None
        return self.serde.loads_typed(data)

    def list(self, config: dict, *, filter=None, before=None, limit=None) -> Iterator:
        thread_id = config["configurable"]["thread_id"]
        keys = self.redis.keys(f"checkpoint:{thread_id}:*")
        for key in sorted(keys, reverse=True):
            data = self.redis.get(key)
            if data:
                yield self.serde.loads_typed(data)

    def put(self, config: dict, checkpoint: Checkpoint, metadata: CheckpointMetadata, new_versions) -> dict:
        thread_id = config["configurable"]["thread_id"]
        step = checkpoint["id"]
        serialized = self.serde.dumps_typed(checkpoint)
        self.redis.set(f"checkpoint:{thread_id}:{step}", serialized)
        self.redis.set(f"checkpoint:{thread_id}:latest", serialized)
        return {**config, "configurable": {**config["configurable"], "checkpoint_id": step}}

import uuid

def get_thread_config(user_id: str, session_id: str = None) -> dict:
    if session_id is None:
        session_id = str(uuid.uuid4())
    thread_id = f"{user_id}:{session_id}"
    return {"configurable": {"thread_id": thread_id}}

# FastAPI handler example
from fastapi import FastAPI
from pydantic import BaseModel

app_api = FastAPI()

class ChatRequest(BaseModel):
    user_id: str
    session_id: str
    message: str

@app_api.post("/chat")
async def chat(req: ChatRequest):
    config = get_thread_config(req.user_id, req.session_id)
    result = await langgraph_app.ainvoke(
        {"messages": [{"role": "user", "content": req.message}]},
        config=config,
    )
    return {"reply": result["messages"][-1].content}

import pytest
from langgraph.checkpoint.memory import MemorySaver

@pytest.fixture
def app():
    # Fresh MemorySaver per test — no cross-test contamination
    return graph.compile(checkpointer=MemorySaver())

def test_multi_turn_memory(app):
    config = {"configurable": {"thread_id": "test-thread"}}

    # Turn 1
    app.invoke({"messages": [{"role": "user", "content": "My name is Bob"}]}, config=config)

    # Turn 2 — name should still be in state
    result = app.invoke(
        {"messages": [{"role": "user", "content": "What is my name?"}]},
        config=config,
    )
    assert "Bob" in result["messages"][-1].content

def test_state_update_applies(app):
    config = {"configurable": {"thread_id": "patch-thread"}}
    app.invoke({"messages": [{"role": "user", "content": "Hello"}]}, config=config)

    # Inject a patch
    app.update_state(config, {"messages": [{"role": "assistant", "content": "Patched reply"}]})
    snapshot = app.get_state(config)
    assert snapshot.values["messages"][-1].content == "Patched reply"

def test_history_length(app):
    config = {"configurable": {"thread_id": "history-thread"}}
    for msg in ["First", "Second", "Third"]:
        app.invoke({"messages": [{"role": "user", "content": msg}]}, config=config)
    history = list(app.get_state_history(config))
    # 3 user turns * at least 1 checkpoint per node = multiple snapshots
    assert len(history) >= 3
